import{_ as e,o as d,c as o,ag as a}from"./chunks/framework.CAXxHpAX.js";const _=JSON.parse('{"title":"Configuration reference","description":"","frontmatter":{"title":"Configuration reference","lang":"en-US"},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":1784458911000}'),r={name:"configuration.md"};function i(s,t,c,n,l,h){return d(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="configuration-reference" tabindex="-1">Configuration reference <a class="header-anchor" href="#configuration-reference" aria-label="Permalink to &quot;Configuration reference&quot;">​</a></h1><p>Piwi is configured entirely through environment variables. It runs with <strong>zero configuration</strong> out of the box — SQLite and local file storage are created automatically under <code>.data/</code>. Set variables only to change a default.</p><p>Variables can go in <code>application/.env</code> (see <code>application/.env.example</code>) or be passed to the container/process. Where a value can also be set in the Settings UI, <strong>the environment variable always wins</strong> and the UI shows that field read-only.</p><div class="tip custom-block"><p class="custom-block-title">Settings UI tooltips</p><p>In the dashboard, every overridable setting shows a help icon next to its label. Hover it to see which <code>PIWI_*</code> env var backs the field, a one-line description, and a link back to this page. Fields that are currently pinned by the environment show a lock badge with the variable name, and the Settings nav marks env-managed pages with a lock icon. The full list of variables and their descriptions is maintained as a typed registry in <code>application/shared/piwi-env-vars.ts</code>.</p></div><h2 id="general" tabindex="-1">General <a class="header-anchor" href="#general" aria-label="Permalink to &quot;General&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_SITE_URL</code></td><td>—</td><td>Public base URL of the instance (e.g. <code>https://piwi.example.com</code>). Used to build links in emails.</td></tr><tr><td><code>PIWI_SECRET_KEY</code></td><td>insecure dev default</td><td>Master key for AES-256-GCM encryption of secrets stored in the database (AI API keys, webhook/SCM secrets). <strong>Strongly recommended in production</strong>, even without auth. Generate with <code>node -e &quot;console.log(require(&#39;node:crypto&#39;).randomBytes(32).toString(&#39;hex&#39;))&quot;</code> (or <code>openssl rand -hex 32</code>).</td></tr></tbody></table><h2 id="database" tabindex="-1">Database <a class="header-anchor" href="#database" aria-label="Permalink to &quot;Database&quot;">​</a></h2><p>Piwi uses SQLite by default. Setting <code>PIWI_DATABASE_URL</code> switches it to PostgreSQL; migrations run automatically on startup.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_DATABASE_PATH</code></td><td><code>.data/piwi.db</code></td><td>Path to the SQLite database file.</td></tr><tr><td><code>PIWI_DATABASE_URL</code></td><td>—</td><td>PostgreSQL connection string (e.g. <code>postgres://user:pass@host:5432/piwi</code>). When set, PostgreSQL is used instead of SQLite.</td></tr><tr><td><code>PIWI_RETENTION_DAYS</code></td><td>— (off)</td><td>Days of test-run history the nightly retention sweep keeps. Unset or <code>0</code> disables automatic run pruning — deleting history is opt-in.</td></tr><tr><td><code>PIWI_RETENTION_NOTIFICATION_DAYS</code></td><td><code>30</code></td><td>Days to keep sent/failed notification outbox rows. <code>0</code> keeps them forever.</td></tr><tr><td><code>PIWI_RETENTION_DIAGNOSIS_VERSIONS</code></td><td><code>20</code></td><td>AI-diagnosis history versions kept per diagnosis. <code>0</code> disables capping.</td></tr></tbody></table><p>See <a href="./deployment.html">Deployment</a> for PostgreSQL setup and <a href="./storage.html#data-retention">Storage → Data retention</a> for how the nightly sweep works.</p><h2 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h2><p>Controls where test artifacts (HTML reports, traces, attachments) are stored.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_STORAGE_TYPE</code></td><td><code>local</code></td><td><code>local</code> or <code>s3</code>.</td></tr><tr><td><code>PIWI_STORAGE_PATH</code></td><td><code>.data/storage</code></td><td>Directory for local storage.</td></tr><tr><td><code>PIWI_S3_BUCKET</code></td><td>—</td><td>Bucket name (S3).</td></tr><tr><td><code>PIWI_S3_REGION</code></td><td>—</td><td>Region (S3).</td></tr><tr><td><code>PIWI_S3_ACCESS_KEY_ID</code></td><td>—</td><td>Access key (S3).</td></tr><tr><td><code>PIWI_S3_SECRET_ACCESS_KEY</code></td><td>—</td><td>Secret key (S3).</td></tr><tr><td><code>PIWI_S3_ENDPOINT</code></td><td>—</td><td>Custom endpoint for S3-compatible services (MinIO, R2, Spaces).</td></tr><tr><td><code>PIWI_S3_FORCE_PATH_STYLE</code></td><td><code>false</code></td><td>Use path-style addressing (required by some S3-compatible services).</td></tr></tbody></table><p>Full details and IAM examples: <a href="./storage.html">Storage configuration</a>.</p><h2 id="authentication" tabindex="-1">Authentication <a class="header-anchor" href="#authentication" aria-label="Permalink to &quot;Authentication&quot;">​</a></h2><p>Authentication is optional and off by default. When disabled, all endpoints behave as a single virtual administrator.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_AUTH_ENABLED</code></td><td><code>false</code></td><td><code>true</code> to enable role-based access control and API keys.</td></tr><tr><td><code>PIWI_AUTH_SECRET</code></td><td>—</td><td>Secret used to sign/encrypt session cookies. Required when auth is enabled.</td></tr><tr><td><code>PIWI_OAUTH_GOOGLE_CLIENT_ID</code></td><td>—</td><td>Google OAuth client ID (optional SSO).</td></tr><tr><td><code>PIWI_OAUTH_GOOGLE_CLIENT_SECRET</code></td><td>—</td><td>Google OAuth client secret.</td></tr><tr><td><code>PIWI_OAUTH_GITHUB_CLIENT_ID</code></td><td>—</td><td>GitHub OAuth client ID (optional SSO).</td></tr><tr><td><code>PIWI_OAUTH_GITHUB_CLIENT_SECRET</code></td><td>—</td><td>GitHub OAuth client secret.</td></tr><tr><td><code>PIWI_OAUTH_ALLOWED_DOMAINS</code></td><td>—</td><td>Comma-separated verified email domains allowed to sign in via OAuth (applies to all providers). When set, only verified emails in these domains are accepted.</td></tr><tr><td><code>PIWI_OAUTH_GITHUB_ALLOWED_ORGS</code></td><td>—</td><td>Comma-separated GitHub org logins a user must belong to. Requests the <code>read:org</code> scope and rejects sign-ins from non-members.</td></tr></tbody></table><blockquote><p>Behind a reverse proxy, set <code>PIWI_SITE_URL</code> so the OAuth <code>redirect_uri</code> is built from your public URL and matches what you registered with the provider (instead of being inferred from the request <code>Host</code>).</p></blockquote><p>See <a href="./authentication.html">Authentication</a> for roles, API keys, and project assignments.</p><h2 id="wasted-time" tabindex="-1">Wasted time <a class="header-anchor" href="#wasted-time" aria-label="Permalink to &quot;Wasted time&quot;">​</a></h2><p>Controls which Playwright wait steps are counted as &quot;wasted time&quot; on the run timeline and in per-test/run totals. Classification happens when a run is viewed, so changing it re-classifies historical runs immediately.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_WASTED_WAIT_PATTERNS</code></td><td><code>Wait for timeout*,*waitForTimeout*</code></td><td>Comma/newline-separated allowlist of glob patterns. A wait is wasted when a pattern matches its step <strong>title</strong> or its source <strong>location</strong>. Case-insensitive; supports <code>*</code> and <code>?</code>. Use <code>*</code> to count every wait. When set, the in-app <strong>Settings → Wasted time</strong> editor is locked.</td></tr></tbody></table><p>When unset, configure the patterns from <strong>Settings → Wasted time</strong> (administrator only). The default counts only explicit <code>waitForTimeout</code> sleeps, since framework-injected waits (load-state, wait-for-function) are usually unavoidable.</p><h2 id="ai-diagnosis" tabindex="-1">AI diagnosis <a class="header-anchor" href="#ai-diagnosis" aria-label="Permalink to &quot;AI diagnosis&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_AI_PROVIDER</code></td><td>—</td><td><code>anthropic</code> or <code>openai</code>.</td></tr><tr><td><code>PIWI_AI_API_KEY</code></td><td>—</td><td>Provider API key.</td></tr><tr><td><code>PIWI_AI_MODEL</code></td><td><code>claude-opus-4-8</code> (Anthropic)</td><td>Model name.</td></tr><tr><td><code>PIWI_AI_BASE_URL</code></td><td>—</td><td>Base URL for OpenAI-compatible providers (e.g. Ollama).</td></tr><tr><td><code>PIWI_AI_AUTO_DIAGNOSE</code></td><td><code>false</code></td><td><code>true</code> to auto-diagnose new clusters on run finish.</td></tr><tr><td><code>PIWI_AI_AUTO_DIAGNOSE_MAX</code></td><td><code>3</code></td><td>Max clusters auto-diagnosed per finished run (budget cap).</td></tr><tr><td><code>PIWI_AI_RESEARCH_PROVIDER</code></td><td>—</td><td>Provider for the optional research (pre-analysis) stage. Falls back to <code>PIWI_AI_PROVIDER</code>.</td></tr><tr><td><code>PIWI_AI_RESEARCH_MODEL</code></td><td>—</td><td>Cheaper/faster model for the research stage. Empty disables the two-stage pipeline.</td></tr><tr><td><code>PIWI_AI_RESEARCH_BASE_URL</code></td><td>—</td><td>Base URL for the research-stage provider. Falls back to <code>PIWI_AI_BASE_URL</code>.</td></tr><tr><td><code>PIWI_AI_RESEARCH_API_KEY</code></td><td>—</td><td>API key for the research-stage provider. Falls back to <code>PIWI_AI_API_KEY</code>.</td></tr><tr><td><code>PIWI_AI_EMBEDDING_PROVIDER</code></td><td>—</td><td>Provider for embeddings (semantic clustering). Falls back to <code>PIWI_AI_PROVIDER</code> when <code>PIWI_AI_EMBEDDING_MODEL</code> is set. Must be OpenAI-compatible — Anthropic has no embeddings API — so the fallback only helps when the main provider is <code>openai</code>.</td></tr><tr><td><code>PIWI_AI_EMBEDDING_MODEL</code></td><td>—</td><td>Embedding model name (e.g. <code>text-embedding-3-small</code>). Empty disables semantic clustering (and the embedding fallbacks).</td></tr><tr><td><code>PIWI_AI_EMBEDDING_BASE_URL</code></td><td>—</td><td>Base URL for the embedding provider. Falls back to <code>PIWI_AI_BASE_URL</code> when <code>PIWI_AI_EMBEDDING_MODEL</code> is set.</td></tr><tr><td><code>PIWI_AI_EMBEDDING_API_KEY</code></td><td>—</td><td>API key for the embedding provider. Falls back to <code>PIWI_AI_API_KEY</code> when <code>PIWI_AI_EMBEDDING_MODEL</code> is set.</td></tr></tbody></table><p>The <code>PIWI_AI_MAX_*</code> and <code>PIWI_AI_SLOW_REQUEST_MS</code> context-limit variables are documented in <a href="./ai-diagnosis.html#context-limits-and-token-cost">AI diagnosis → Context limits</a>.</p><h2 id="ingest-limits" tabindex="-1">Ingest limits <a class="header-anchor" href="#ingest-limits" aria-label="Permalink to &quot;Ingest limits&quot;">​</a></h2><p>Caps applied to per-execution payloads (console output, steps, ARIA snapshots, error text, source snippets) before they are stored. They bound database growth against verbose or hostile submitters; values above each limit are truncated with a visible marker. Distinct from the <code>PIWI_AI_MAX_*</code> limits, which bound what enters an AI diagnosis prompt — the storage defaults sit at or above the AI maxima so the AI limits stay the binding constraint for prompts. Environment-only (no settings UI).</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_INGEST_MAX_CONSOLE_ENTRIES</code></td><td><code>200</code></td><td>Max console entries stored per execution (first 20 + newest kept, with a drop marker).</td></tr><tr><td><code>PIWI_INGEST_MAX_CONSOLE_ENTRY_CHARS</code></td><td><code>2000</code></td><td>Max characters stored per console entry.</td></tr><tr><td><code>PIWI_INGEST_MAX_STEPS</code></td><td><code>500</code></td><td>Max test steps stored per execution.</td></tr><tr><td><code>PIWI_INGEST_MAX_STEP_EVENTS</code></td><td><code>1000</code></td><td>Max step events stored per execution.</td></tr><tr><td><code>PIWI_INGEST_MAX_ARIA_CHARS</code></td><td><code>100000</code></td><td>Max characters of the ARIA snapshot stored per failing execution.</td></tr><tr><td><code>PIWI_INGEST_MAX_ERROR_CHARS</code></td><td><code>20000</code></td><td>Max characters of error text stored per execution (head and tail are kept).</td></tr><tr><td><code>PIWI_INGEST_MAX_SAMPLE_ERROR_CHARS</code></td><td><code>50000</code></td><td>Max characters of the sample error stored per failure cluster.</td></tr><tr><td><code>PIWI_INGEST_MAX_TEST_SOURCE_CHARS</code></td><td><code>50000</code></td><td>Max characters of the test source snippet stored per failing execution.</td></tr><tr><td><code>PIWI_INGEST_MAX_SOURCE_FRAMES</code></td><td><code>8</code></td><td>Max source stack frames stored per failing execution.</td></tr><tr><td><code>PIWI_INGEST_MAX_SOURCE_FRAME_CHARS</code></td><td><code>4000</code></td><td>Max characters per stored source frame snippet.</td></tr></tbody></table><h2 id="timeline-markers" tabindex="-1">Timeline markers <a class="header-anchor" href="#timeline-markers" aria-label="Permalink to &quot;Timeline markers&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_AUTO_MARKERS</code></td><td><code>true</code></td><td>Automatically create a <a href="./timeline-markers.html">timeline marker</a> when a run&#39;s Playwright or reporter version changes from the previous run in the same environment. Set to <code>false</code> to disable.</td></tr></tbody></table><h2 id="email-smtp" tabindex="-1">Email (SMTP) <a class="header-anchor" href="#email-smtp" aria-label="Permalink to &quot;Email (SMTP)&quot;">​</a></h2><p>Required for email notifications and account flows (verification, password reset, invites). Set via environment only.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_SMTP_HOST</code></td><td>—</td><td>SMTP hostname.</td></tr><tr><td><code>PIWI_SMTP_PORT</code></td><td><code>587</code></td><td>SMTP port.</td></tr><tr><td><code>PIWI_SMTP_USER</code></td><td>—</td><td>SMTP username.</td></tr><tr><td><code>PIWI_SMTP_PASS</code></td><td>—</td><td>SMTP password (never returned by the API).</td></tr><tr><td><code>PIWI_SMTP_FROM</code></td><td>—</td><td>From address.</td></tr><tr><td><code>PIWI_SMTP_FROM_NAME</code></td><td>—</td><td>From display name (optional).</td></tr><tr><td><code>PIWI_SMTP_SECURE</code></td><td><code>false</code></td><td><code>true</code> for port 465 (implicit TLS).</td></tr></tbody></table><p>See <a href="./notifications.html">Notifications</a> for channels and subscriptions.</p><h2 id="failure-clustering" tabindex="-1">Failure clustering <a class="header-anchor" href="#failure-clustering" aria-label="Permalink to &quot;Failure clustering&quot;">​</a></h2><p>Tunes the similarity thresholds used when grouping failures into clusters by their error fingerprint (and optional embeddings).</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_CLUSTER_SIMILARITY_THRESHOLD</code></td><td><code>0.92</code></td><td>Cosine similarity (0–1) above which two failure embeddings merge into one cluster.</td></tr><tr><td><code>PIWI_CLUSTER_SUGGEST_THRESHOLD</code></td><td><code>0.80</code></td><td>Similarity at which a failure is suggested (not auto-merged) as related to a cluster. Capped at the merge threshold.</td></tr></tbody></table><p>See <a href="./ai-diagnosis.html#failure-clustering">AI diagnosis → Failure clustering</a>.</p><h2 id="build-time" tabindex="-1">Build-time <a class="header-anchor" href="#build-time" aria-label="Permalink to &quot;Build-time&quot;">​</a></h2><p>These affect how the app is built rather than how a running instance behaves, and are mostly for contributors.</p><table tabindex="0"><thead><tr><th>Variable</th><th>Description</th></tr></thead><tbody><tr><td><code>PIWI_DEMO_MODE</code></td><td>Build a fully client-side demo SPA (no server) backed by in-browser SQLite.</td></tr><tr><td><code>PIWI_BUILD_DIR</code></td><td>Override the build output directory.</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Variables prefixed <code>PIWI_*_TEST_*</code>, <code>PIWI_MAILPIT_*</code>, and <code>PIWI_POSTGRES_TEST_URL</code> exist only for the functional test harness and are not used by a normal deployment.</p></div>',43)])])}const p=e(r,[["render",i]]);export{_ as __pageData,p as default};
